SourceCode.Declaration:
/// <summary>
/// Contract class is used for Creditnote
/// </summary>
class ETGCreditNoteContract
{
    LedgerJournalId  ledgerJournalId;
    ReportName       reportName;
}

Method.Source:
[DataMemberAttribute("Journal Number")]
public LedgerJournalId parmJournalNum(LedgerJournalId _ledgerJournalId = ledgerJournalId)
{
    ledgerJournalId = _ledgerJournalId;
    return             ledgerJournalId;
}

[DataMemberAttribute("Report name")]
public ReportName parmReportName(ReportName _reportName = reportName)
{
    reportName = _reportName;
    return        reportName;
}
